import type { Config } from 'tailwindcss'

const config: Config = {
  darkMode: ['class'],
  content: [
    './pages/**/*.{ts,tsx}',
    './components/**/*.{ts,tsx}',
    './app/**/*.{ts,tsx}',
    './src/**/*.{ts,tsx}',
  ],
  theme: {
    container: {
      center: true,
      padding: '2rem',
      screens: { '2xl': '1400px' },
    },
    extend: {
      colors: {
        border: 'hsl(var(--border))',
        input: 'hsl(var(--input))',
        ring: 'hsl(var(--ring))',
        background: 'hsl(var(--background))',
        foreground: 'hsl(var(--foreground))',
        primary: {
          DEFAULT: 'hsl(var(--primary))',
          foreground: 'hsl(var(--primary-foreground))',
        },
        secondary: {
          DEFAULT: 'hsl(var(--secondary))',
          foreground: 'hsl(var(--secondary-foreground))',
        },
        destructive: {
          DEFAULT: 'hsl(var(--destructive))',
          foreground: 'hsl(var(--destructive-foreground))',
        },
        muted: {
          DEFAULT: 'hsl(var(--muted))',
          foreground: 'hsl(var(--muted-foreground))',
        },
        accent: {
          DEFAULT: 'hsl(var(--accent))',
          foreground: 'hsl(var(--accent-foreground))',
        },
        popover: {
          DEFAULT: 'hsl(var(--popover))',
          foreground: 'hsl(var(--popover-foreground))',
        },
        card: {
          DEFAULT: 'hsl(var(--card))',
          foreground: 'hsl(var(--card-foreground))',
        },
      },
      borderRadius: {
        lg: 'var(--radius)',
        md: 'calc(var(--radius) - 2px)',
        sm: 'calc(var(--radius) - 4px)',
      },
      typography: {
        DEFAULT: { css: { '--tw-prose-body': 'hsl(var(--foreground))' } },
      },
    },
  },
  plugins: [require('@tailwindcss/typography')],
}

export default config

@tailwind base;
@tailwind components;
@tailwind utilities;

/* GitHub Dark syntax highlighting */
@import 'highlight.js/styles/github-dark.css';

@layer base {
  :root {
    --background: 0 0% 98%;
    --foreground: 222 47% 11%;
    --card: 0 0% 100%;
    --card-foreground: 222 47% 11%;
    --popover: 0 0% 100%;
    --popover-foreground: 222 47% 11%;
    --primary: 239 84% 67%;
    --primary-foreground: 0 0% 100%;
    --secondary: 210 40% 96%;
    --secondary-foreground: 222 47% 11%;
    --muted: 210 40% 96%;
    --muted-foreground: 215 16% 47%;
    --accent: 210 40% 96%;
    --accent-foreground: 222 47% 11%;
    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 100%;
    --border: 214 32% 91%;
    --input: 214 32% 91%;
    --ring: 239 84% 67%;
    --radius: 0.5rem;
  }

  .dark {
    --background: 222 47% 8%;
    --foreground: 210 40% 98%;
    --card: 222 47% 11%;
    --card-foreground: 210 40% 98%;
    --popover: 222 47% 11%;
    --popover-foreground: 210 40% 98%;
    --primary: 239 84% 67%;
    --primary-foreground: 0 0% 100%;
    --secondary: 217 33% 17%;
    --secondary-foreground: 210 40% 98%;
    --muted: 217 33% 17%;
    --muted-foreground: 215 20% 65%;
    --accent: 217 33% 17%;
    --accent-foreground: 210 40% 98%;
    --destructive: 0 62% 50%;
    --destructive-foreground: 0 0% 100%;
    --border: 217 33% 17%;
    --input: 217 33% 17%;
    --ring: 239 84% 67%;
  }
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
  }
}

/* Code block styling — GitHub Dark theme */
.prose-custom pre {
  @apply rounded-lg overflow-hidden my-4;
  border: 1px solid #30363d;
}

.prose-custom pre code {
  @apply bg-transparent p-0 text-sm font-mono;
  display: block;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}

.prose-custom code:not(pre code) {
  @apply px-1.5 py-0.5 rounded text-sm font-mono;
  background: rgba(110, 118, 129, 0.2);
  color: #e6edf3;
}

/* Smooth scrolling */
html {
  scroll-behavior: smooth;
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  @apply bg-transparent;
}

::-webkit-scrollbar-thumb {
  @apply bg-muted-foreground/30 rounded-full;
}

/* Focus visible */
:focus-visible {
  @apply outline-none ring-2 ring-ring ring-offset-2 ring-offset-background;
}

/* Better prose for articles */
.prose-custom {
  @apply text-base leading-relaxed;
}

.prose-custom h1,
.prose-custom h2,
.prose-custom h3,
.prose-custom h4 {
  @apply font-bold tracking-tight;
}

.prose-custom h2 {
  @apply text-2xl mt-10 mb-4;
}

.prose-custom h3 {
  @apply text-xl mt-8 mb-3;
}

.prose-custom p {
  @apply my-4;
}

.prose-custom ul,
.prose-custom ol {
  @apply my-4 pl-6;
}

.prose-custom li {
  @apply my-1;
}

.prose-custom ul li {
  @apply list-disc;
}

.prose-custom ol li {
  @apply list-decimal;
}

.prose-custom blockquote {
  @apply border-l-4 border-primary/50 pl-4 italic text-muted-foreground my-4;
}

/* Code blocks with GitHub Dark theme */
.prose-custom pre {
  @apply rounded-lg my-4;
  border: 1px solid #30363d;
  background: #161b22 !important;
}

.prose-custom pre code {
  display: block;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  @apply bg-transparent p-0 text-sm font-mono;
}

/* Inline code */
.prose-custom code:not(pre code) {
  @apply px-1.5 py-0.5 rounded text-sm font-mono;
  background: rgba(110, 118, 129, 0.2);
  color: #e6edf3;
}

/* Animation utilities */
@keyframes fade-in {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-fade-in {
  animation: fade-in 0.3s ease-out forwards;
}

/* Glass effect */
.glass {
  @apply bg-background/80 backdrop-blur-md;
}

/* Animated gradient text */
@keyframes gradient-shift {
  0%, 100% { background-position: 0% center; }
  50% { background-position: 200% center; }
}

.animate-gradient {
  animation: gradient-shift 4s ease infinite;
}

/* Glow effect */
.glow-primary {
  box-shadow: 0 0 20px rgba(99, 102, 241, 0.3);
}

/* Article card featured badge */
.badge-featured {
  position: absolute;
  top: 12px;
  right: 12px;
  z-index: 10;
}

/* Apple-style article card animations */
.article-card {
  will-change: transform;
  transition: transform 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94),
              box-shadow 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94),
              border-color 0.3s ease;
}
.article-card:hover {
  transform: translateY(-4px) scale(1.01);
}
.article-card-img {
  transition: transform 0.7s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.article-card:hover .article-card-img {
  transform: scale(1.08);
}
.article-card-arrow {
  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1), color 0.3s ease;
}
.article-card:hover .article-card-arrow {
  transform: translateX(4px);
}

/* Music page Apple-style smoothness */
.music-track-item {
  will-change: background, transform;
  transition: background 0.25s ease, transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.music-track-item:hover {
  transform: translateX(2px);
}
.music-mood-card {
  will-change: transform, box-shadow, border-color;
  transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
              box-shadow 0.3s ease, border-color 0.3s ease;
}
.music-mood-card:hover {
  transform: translateY(-3px);
}
.music-play-btn {
  will-change: transform, box-shadow;
  transition: transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1),
              box-shadow 0.2s ease, background 0.2s ease;
}
.music-play-btn:hover {
  transform: scale(1.05);
}
.music-play-btn:active {
  transform: scale(0.95);
}
@keyframes track-enter {
  0% { opacity: 0; transform: translateY(8px); }
  100% { opacity: 1; transform: translateY(0); }
}
.music-track-enter {
  animation: track-enter 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
}

'use client'

import { useEffect, useRef } from 'react'

interface Bubble {
  x: number
  y: number
  size: number
  opacity: number
  speed: number
  dx: number
  dy: number
}

interface SectionParticlesProps {
  /** CSS color for bubbles, e.g. 'rgba(139, 92, 246, 0.3)' */
  color?: string
  count?: number
  className?: string
}

export function SectionParticles({
  color = 'rgba(139, 92, 246, 0.25)',
  count = 20,
  className = '',
}: SectionParticlesProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext('2d')
    if (!ctx) return

    let raf: number
    let bubbles: Bubble[] = []

    const resize = () => {
      if (!canvas) return
      canvas.width = canvas.offsetWidth
      canvas.height = canvas.offsetHeight
    }

    const initBubbles = () => {
      bubbles = Array.from({ length: count }, () => ({
        x: Math.random() * (canvas?.width ?? 800),
        y: Math.random() * (canvas?.height ?? 400),
        size: Math.random() * 6 + 2,
        opacity: Math.random() * 0.3 + 0.05,
        speed: Math.random() * 0.4 + 0.1,
        dx: (Math.random() - 0.5) * 0.3,
        dy: -(Math.random() * 0.5 + 0.1),
      }))
    }

    const draw = () => {
      if (!canvas || !ctx) return
      ctx.clearRect(0, 0, canvas.width, canvas.height)

      bubbles.forEach((b) => {
        // Move
        b.x += b.dx
        b.y += b.dy

        // Wrap edges
        if (b.y < -b.size) {
          b.y = canvas.height + b.size
          b.x = Math.random() * canvas.width
        }
        if (b.x < -b.size) b.x = canvas.width + b.size
        if (b.x > canvas.width + b.size) b.x = -b.size

        // Draw bubble
        ctx.beginPath()
        ctx.arc(b.x, b.y, b.size, 0, Math.PI * 2)
        ctx.fillStyle = color.replace(/[\d.]+\)$/, `${b.opacity})`)
        ctx.fill()

        // Highlight dot (top-left shine)
        ctx.beginPath()
        ctx.arc(b.x - b.size * 0.25, b.y - b.size * 0.25, b.size * 0.25, 0, Math.PI * 2)
        ctx.fillStyle = `rgba(255, 255, 255, ${b.opacity * 0.8})`
        ctx.fill()
      })

      raf = requestAnimationFrame(draw)
    }

    const observer = new ResizeObserver(() => {
      resize()
    })
    observer.observe(canvas)
    resize()
    initBubbles()
    draw()

    return () => {
      cancelAnimationFrame(raf)
      observer.disconnect()
    }
  }, [color, count])

  return (
    <canvas
      ref={canvasRef}
      className={`absolute inset-0 w-full h-full pointer-events-none ${className}`}
      style={{ overflow: 'hidden' }}
    />
  )
}
